const WebSocket = require('ws');

class GameServer {
    constructor(port) {
        this.wss = new WebSocket.Server({ port });
        this.players = new Map();
        this.TICK_RATE = 60;
        this.PLAYER_SPEED = 200; // pixels per second
        this.MAX_ALLOWED_INPUT_AGE_MS = 200;
        this.lastTickTime = Date.now();

        this.wss.on('connection', (ws) => this.onConnection(ws));

        // Server-authoritative game loop with server-calculated delta time
        setInterval(() => this.serverTick(), 1000 / this.TICK_RATE);

        console.log(`Game server running on port ${port}`);
    }

    onConnection(ws) {
        const playerId = this.generateId();
        const player = {
            id: playerId,
            x: Math.random() * 400 + 100,
            y: Math.random() * 400 + 100,
            inputX: 0,
            inputY: 0,
            distanceTraveled: 0,
            ws: ws,
            lastInputSequence: 0
        };
        this.players.set(playerId, player);

        ws.send(JSON.stringify({
            type: 'init',
            playerId: playerId,
            state: this.getWorldState()
        }));

        this.broadcast({
            type: 'playerJoined',
            player: { id: playerId, x: player.x, y: player.y, distanceTraveled: 0 }
        }, playerId);

        ws.on('message', (data) => this.onMessage(playerId, data));
        ws.on('close', () => this.onDisconnect(playerId));
    }

    onMessage(playerId, data) {
        const player = this.players.get(playerId);
        if (!player) return;

        let msg;
        try {
            msg = JSON.parse(data);
        } catch (e) {
            return; // Ignore malformed messages
        }

        if (msg.type === 'input') {
            // SECURE: We only accept directional input, NOT positions or delta times
            // The server calculates all movement using its own clock
            const inputX = Number(msg.inputX);
            const inputY = Number(msg.inputY);

            if (!Number.isFinite(inputX) || !Number.isFinite(inputY)) return;

            // Normalize input to prevent diagonal speed boost
            const magnitude = Math.sqrt(inputX * inputX + inputY * inputY);
            if (magnitude > 0) {
                player.inputX = inputX / Math.max(magnitude, 1);
                player.inputY = inputY / Math.max(magnitude, 1);
            } else {
                player.inputX = 0;
                player.inputY = 0;
            }

            // Track input sequence for client-side reconciliation
            if (Number.isFinite(msg.sequence)) {
                player.lastInputSequence = msg.sequence;
            }
        }
    }

    serverTick() {
        const now = Date.now();
        // SECURE: Delta time is calculated by the SERVER, never trusted from client
        const deltaTime = Math.min((now - this.lastTickTime) / 1000, 0.1); // Cap at 100ms
        this.lastTickTime = now;

        for (const [id, player] of this.players) {
            const prevX = player.x;
            const prevY = player.y;

            // Server calculates movement using server-side delta time
            const moveX = player.inputX * this.PLAYER_SPEED * deltaTime;
            const moveY = player.inputY * this.PLAYER_SPEED * deltaTime;

            player.x += moveX;
            player.y += moveY;

            // Clamp to world bounds
            player.x = Math.max(0, Math.min(1200, player.x));
            player.y = Math.max(0, Math.min(800, player.y));

            // Server calculates distance traveled
            const dx = player.x - prevX;
            const dy = player.y - prevY;
            player.distanceTraveled += Math.sqrt(dx * dx + dy * dy);
        }

        // Broadcast authoritative state to all clients
        this.broadcast({
            type: 'state',
            timestamp: now,
            players: this.getWorldState()
        });
    }

    getWorldState() {
        const state = [];
        for (const [id, player] of this.players) {
            state.push({
                id: player.id,
                x: player.x,
                y: player.y,
                distanceTraveled: Math.round(player.distanceTraveled * 100) / 100,
                lastInputSequence: player.lastInputSequence
            });
        }
        return state;
    }

    broadcast(msg, excludeId = null) {
        const data = JSON.stringify(msg);
        for (const [id, player] of this.players) {
            if (id !== excludeId && player.ws.readyState === WebSocket.OPEN) {
                player.ws.send(data);
            }
        }
    }

    onDisconnect(playerId) {
        this.players.delete(playerId);
        this.broadcast({ type: 'playerLeft', playerId });
    }

    generateId() {
        const bytes = require('crypto').randomBytes(16);
        return bytes.toString('hex');
    }
}

const server = new GameServer(8080);


// ============================================
// CLIENT SIDE (Browser)
// ============================================

const clientCode = `
<!DOCTYPE html>
<html>
<head>
    <title>Secure Racing Game</title>
    <style>
        * { margin: 0; padding: 0; box-sizing: border-box; }
        body { background: #1a1a2e; display: flex; flex-direction: column; align-items: center; font-family: monospace; color: #eee; }
        canvas { border: 2px solid #16213e; margin-top: 10px; }
        #scoreboard { margin: 10px; padding: 10px; background: #16213e; border-radius: 5px; min-width: 300px; }
        #scoreboard h3 { color: #e94560; margin-bottom: 5px; }
        .score-entry { display: flex; justify-content: space-between; padding: 2px 0; }
        .you { color: #0f3460; font-weight: bold; }
        #status { color: #e94560; margin-top: 5px; }
    </style>
</head>
<body>
    <div id="status">Connecting...</div>
    <div id="scoreboard"><h3>🏁 Race Scoreboard</h3><div id="scores"></div></div>
    <canvas id="gameCanvas" width="1200" height="800"></canvas>

    <script>
    (function() {
        'use strict';

        const canvas = document.getElementById('gameCanvas');
        const ctx = canvas.getContext('2d');
        const statusEl = document.getElementById('status');
        const scoresEl = document.getElementById('scores');

        // Game state
        let myPlayerId = null;
        let players = new Map();
        let inputSequence = 0;
        let pendingInputs = [];
        let connected = false;

        // Input state - only directional, no timing manipulation possible
        const keys = {};

        // Prevent default for game keys
        const gameKeys = new Set(['ArrowUp', 'ArrowDown', 'ArrowLeft', 'ArrowRight', 'KeyW', 'KeyA', 'KeyS', 'KeyD']);

        document.addEventListener('keydown', (e) => {
            if (gameKeys.has(e.code)) {
                e.preventDefault();
                keys[e.code] = true;
            }
        });

        document.addEventListener('keyup', (e) => {
            if (gameKeys.has(e.code)) {
                e.preventDefault();
                keys[e.code] = false;
            }
        });

        // Prevent focus loss issues
        window.addEventListener('blur', () => {
            for (const key in keys) keys[key] = false;
        });

        // WebSocket connection
        let ws = null;

        function connect() {
            const protocol = location.protocol === 'https:' ? 'wss:' : 'ws:';
            ws = new WebSocket(protocol + '//' + location.hostname + ':8080');

            ws.onopen = () => {
                connected = true;
                statusEl.textContent = 'Connected!';
                statusEl.style.color = '#4ecca3';
            };

            ws.onmessage = (event) => {
                let msg;
                try {
                    msg = JSON.parse(event.data);
                } catch (e) {
                    return;
                }
                handleServerMessage(msg);
            };

            ws.onclose = () => {
                connected = false;
                statusEl.textContent = 'Disconnected. Reconnecting...';
                statusEl.style.color = '#e94560';
                setTimeout(connect, 2000);
            };

            ws.onerror = () => {
                ws.close();
            };
        }

        function handleServerMessage(msg) {
            switch (msg.type) {
                case 'init':
                    myPlayerId = msg.playerId;
                    players.clear();
                    for (const p of msg.state) {
                        players.set(p.id, {
                            x: p.x, y: p.y,
                            targetX: p.x, targetY: p.y,
                            distanceTraveled: p.distanceTraveled
                        });
                    }
                    break;

                case 'state':
                    // Apply authoritative server state
                    for (const p of msg.players) {
                        let existing = players.get(p.id);
                        if (!existing) {
                            existing = { x: p.x, y: p.y, targetX: p.x, targetY: p.y, distanceTraveled: 0 };
                            players.set(p.id, existing);
                        }

                        if (p.id === myPlayerId) {
                            // Server reconciliation for local player
                            existing.x = p.x;
                            existing.y = p.y;
                            existing.targetX = p.x;
                            existing.targetY = p.y;

                            // Remove acknowledged inputs
                            pendingInputs = pendingInputs.filter(
                                input => input.sequence > p.lastInputSequence
                            );

                            // Re-apply unacknowledged inputs for client-side prediction
                            // Using a fixed step size for prediction (no client delta time abuse)
                            const PREDICTION_STEP = 1 / 60;
                            const PLAYER_SPEED = 200;
                            for (const input of pendingInputs) {
                                existing.x += input.inputX * PLAYER_SPEED * PREDICTION_STEP;
                                existing.y += input.inputY * PLAYER_SPEED * PREDICTION_STEP;
                                existing.x = Math.max(0, Math.min(1200, existing.x));
                                existing.y = Math.max(0, Math.min(800, existing.y));
                            }
                        } else {
                            // Interpolate other players for smooth rendering
                            existing.targetX = p.x;
                            existing.targetY = p.y;
                        }

                        existing.distanceTraveled = p.distanceTraveled;
                    }
                    break;

                case 'playerJoined':
                    players.set(msg.player.id, {
                        x: msg.player.x, y: msg.player.y,
                        targetX: msg.player.x, targetY: msg.player.y,
                        distanceTraveled: 0
                    });
                    break;

                case 'playerLeft':
                    players.delete(msg.playerId);
                    break;
            }
        }

        // Send only directional input to server - NO delta time, NO position
        function sendInput() {
            if (!connected || !ws || ws.readyState !== WebSocket.OPEN) return;

            let inputX = 0;
            let inputY = 0;

            if (keys['ArrowLeft'] || keys['KeyA']) inputX -= 1;
            if (keys['ArrowRight'] || keys['KeyD']) inputX += 1;
            if (keys['ArrowUp'] || keys['KeyW']) inputY -= 1;
            if (keys['ArrowDown'] || keys['KeyS']) inputY += 1;

            inputSequence++;

            const inputMsg = {
                type: 'input',
                inputX: inputX,
                inputY: inputY,
                sequence: inputSequence
            };

            // Store for client-side prediction reconciliation
            const magnitude = Math.sqrt(inputX * inputX + inputY * inputY);
            pendingInputs.push({
                sequence: inputSequence,
                inputX: magnitude > 0 ? inputX / magnitude : 0,
                inputY: magnitude > 0 ? inputY / magnitude : 0
            });

            // Limit pending inputs buffer
            if (pendingInputs.length > 120) {
                pendingInputs = pendingInputs.slice(-60);
            }

            ws.send(JSON.stringify(inputMsg));
        }

        // Rendering
        const INTERPOLATION_SPEED = 0.15;

        function render() {
            ctx.fillStyle = '#1a1a2e';
            ctx.fillRect(0, 0, canvas.width, canvas.height);

            // Draw grid
            ctx.strokeStyle = '#16213e';
            ctx.lineWidth = 1;
            for (let x = 0; x < canvas.width; x += 50) {
                ctx.beginPath();
                ctx.moveTo(x, 0);
                ctx.lineTo(x, canvas.height);
                ctx.stroke();
            }
            for (let y = 0; y < canvas.height; y += 50) {
                ctx.beginPath();
                ctx.moveTo(0, y);
                ctx.lineTo(canvas.width, y);
                ctx.stroke();
            }

            // Draw race track markers
            drawTrackMarkers();

            // Draw players
            for (const [id, player] of players) {
                const isMe = id === myPlayerId;

                // Interpolate other players toward their target positions
                if (!isMe) {
                    player.x += (player.targetX - player.x) * INTERPOLATION_SPEED;
                    player.y += (player.targetY - player.y) * INTERPOLATION_SPEED;
                }

                // Player body
                ctx.fillStyle = isMe ? '#e94560' : '#0f3460';
                ctx.strokeStyle = isMe ? '#ff6b6b' : '#4a90d9';
                ctx.lineWidth = 2;

                ctx.beginPath();
                ctx.arc(player.x, player.y, 15, 0, Math.PI * 2);
                ctx.fill();
                ctx.stroke();

                // Player label
                ctx.fillStyle = '#eee';
                ctx.font = '11px monospace';
                ctx.textAlign = 'center';
                const label = isMe ? 'YOU' : id.substring(0, 6);
                ctx.fillText(label, player.x, player.y - 22);

                // Distance indicator
                ctx.fillStyle = '#4ecca3';
                ctx.font = '10px monospace';
                ctx.fillText(Math.round(player.distanceTraveled) + 'px', player.x, player.y + 30);

                // Direction indicator for local player
                if (isMe) {
                    let dirX = 0, dirY = 0;
                    if (keys['ArrowLeft'] || keys['KeyA']) dirX -= 1;
                    if (keys['ArrowRight'] || keys['KeyD']) dirX += 1;
                    if (keys['ArrowUp'] || keys['KeyW']) dirY -= 1;
                    if (keys['ArrowDown'] || keys['KeyS']) dirY += 1;
                    if (dirX !== 0 || dirY !== 0) {
                        const mag = Math.sqrt(dirX * dirX + dirY * dirY);
                        ctx.strokeStyle = '#e94560';
                        ctx.lineWidth = 2;
                        ctx.beginPath();
                        ctx.moveTo(player.x, player.y);
                        ctx.lineTo(player.x + (dirX / mag) * 25, player.y + (dirY / mag) * 25);
                        ctx.stroke();
                    }
                }
            }

            // Draw HUD
            drawHUD();

            // Update scoreboard
            updateScoreboard();
        }

        function drawTrackMarkers() {
            const checkpoints = [
                { x: 100, y: 100 }, { x: 600, y: 100 }, { x: 1100, y: 100 },
                { x: 1100, y: 400 }, { x: 1100, y: 700 }, { x: 600, y: 700 },
                { x: 100, y: 700 }, { x: 100, y: 400 }
            ];

            ctx.strokeStyle = '#e94560';
            ctx.lineWidth = 2;
            ctx.setLineDash([10, 10]);
            ctx.beginPath();
            ctx.moveTo(checkpoints[0].x, checkpoints[0].y);
            for (let i = 1; i < checkpoints.length; i++) {
                ctx.lineTo(checkpoints[i].x, checkpoints[i].y);
            }
            ctx.closePath();
            ctx.stroke();
            ctx.setLineDash([]);

            for (const cp of checkpoints) {
                ctx.fillStyle = '#e94560';
                ctx.beginPath();
                ctx.arc(cp.x, cp.y, 8, 0, Math.PI * 2);
                ctx.fill();
            }
        }

        function drawHUD() {
            const me = players.get(myPlayerId);
            if (!me) return;

            ctx.fillStyle = 'rgba(22, 33, 62, 0.8)';
            ctx.fillRect(10, 10, 250, 60);

            ctx.fillStyle = '#4ecca3';
            ctx.font = '14px monospace';
            ctx.textAlign = 'left';
            ctx.fillText('Distance: ' + Math.round(me.distanceTraveled) + ' px', 20, 32);
            ctx.fillText('Players: ' + players.size, 20, 52);

            ctx.fillStyle = 'rgba(22, 33, 62, 0.8)';
            ctx.fillRect(canvas.width - 260, 10, 250, 40);
            ctx.fillStyle = '#e94560';
            ctx.font = '11px monospace';
            ctx.textAlign = 'right';
            ctx.fillText('WASD / Arrow Keys to move', canvas.width - 20, 35);
        }

        function updateScoreboard() {
            const sorted = Array.from(players.entries())
                .map(([id, p]) => ({ id, dist: p.distanceTraveled }))
                .sort((a, b) => b.dist - a.dist);

            let html = '';
            for (let i = 0; i < sorted.length; i++) {
                const p = sorted[i];
                const isMe = p.id === myPlayerId;
                const name = isMe ? '⭐ YOU' : p.id.substring(0, 8);
                const cls = isMe ? ' class="you"' : '';
                html += '<div class="score-entry"' + cls + '>';
                html += '<span>#' + (i + 1) + ' ' + name + '</span>';
                html += '<span>' + Math.round(p.dist) + ' px</span>';
                html += '</div>';
            }
            scoresEl.innerHTML = html;
        }

        // Game loop - uses setInterval as required
        // Input is sent at a fixed rate; rendering interpolates
        const INPUT_RATE = 60; // Send input 60 times per second
        const RENDER_RATE = 60;

        setInterval(sendInput, 1000 / INPUT_RATE);
        setInterval(render, 1000 / RENDER_RATE);

        // Connect to server
        connect();

        console.log('%c[SECURITY] This game uses server-authoritative movement.', 'color: #4ecca3; font-weight: bold;');
        console.log('%c[SECURITY] Delta time is calculated server-side only.', 'color: #4ecca3;');
        console.log('%c[SECURITY] Client sends only directional input (no positions or timing).', 'color: #4ecca3;');
    })();
    </script>
</body>
</html>
`;

// Serve the client HTML
const http = require('http');
const httpServer = http.createServer((req, res) => {
    // Basic security headers
    res.setHeader('Content-Type', 'text/html; charset=utf-8');
    res.setHeader('X-Content-Type-Options', 'nosniff');
    res.setHeader('X-Frame-Options', 'DENY');
    res.setHeader('Content-Security-Policy',
        "default-src 'self'; script-src 'unsafe-inline'; style-src 'unsafe-inline'; connect-src ws: wss:;");
    res.writeHead(200);
    res.end(clientCode);
});

httpServer.listen(3000, () => {
    console.log('HTTP server running on http://localhost:3000');
});